frame_eqs:
wave_r = 0.5 + 0.5*sin(6*time);
wave_g = 0.5 + 0.5*sin(4.1*time);
wave_b = -1 + (1-wave_r + 1-wave_g);
warp = 0;
q1 = wave_r;
q2 = wave_g;
q3 = wave_b;

pixel_eqs:
thresh = above(bass_att,thresh)*2+(1-above(bass_att,thresh))*((thresh-1.3)*0.96+1.3);
dx_r = equal(thresh,2)*0.015*sin(5*time)+(1-equal(thresh,2))*dx_r;
dy_r = equal(thresh,2)*0.015*sin(6*time)+(1-equal(thresh,2))*dy_r;

crude = 5*abs(3*cos(bass_att-12*rad)*(4*rad*sin(4*ang)));
arc = cos(12*cos(2-abs(cos(2*rad-sin(12*ang)))));
cinc = above(sin(bass_att),1)*arc + below(sin(bass_att),0.9)*crude;
zoom = zoom + 0.1;
dx = dx + dx_r*cinc;
dy = dy + dy_r*cinc;
du = (x*2-1) - q1;
dv = (y*2-1) - q2;
dist = sqrt(du*du+dv*dv);
ang2 = atan2(du,dv) + time*0.15;
mult = 0.65*sin(dist*0.05);
dx = mult*sin(ang2*2-1.5);
dy = mult*cos(ang2*2-1.5);
rot=0.1*pow(-ang,3)-1.18*sin(ang);
zoom=2*sin(-rad)+1.3+ sin(rad);
dx = dx + 0.09*sin(q8*0.785);
dy = dy + 0.09*sin(q8*0.675);
zoom = zoom +q7;

